import { render } from '../../core/engine.js';
import { renderLoginForm, renderLoginPage } from './render.js';
import { state, users, masters, salons, salonStaff } from '../../state.js';
import { showToast, validatePhone } from '../../utils.js';

export function handleLogin() {
    const phone = state.loginPhone.trim();
    const password = state.loginPassword;

    if (!phone) { state.authError = 'Введите номер телефона'; render(); return; }
    if (!password) { state.authError = 'Введите пароль'; render(); return; }

    const user = users.find(u => u.phone === phone && u.password === password);
    if (!user) {
        state.authError = 'Неверный номер телефона или пароль';
        render();
        return;
    }

    state.currentUser = user;
    if (user.theme) {
        document.body.dataset.theme = user.theme;
    } else if (user.gender === 'male') {
        user.theme = 'masculine';
        document.body.dataset.theme = 'masculine';
    } else {
        user.theme = '';
        document.body.dataset.theme = '';
    }
    state.isAuthenticated = true;
    state.authMode = 'login';
    state.authError = '';
    state.currentPage = 'home';
    state.loginPhone = '';
    state.loginPassword = '';

    // Pre-fill booking client info
    state.bookingData.clientName = user.name || '';
    state.bookingData.clientPhone = user.phone || '';

    state.showAuthPage = false;
    showToast('Добро пожаловать, ' + (user.name || user.phone) + '!');
    render();
}

window.handleLogin = handleLogin;

export function handleRegStep1() {
    state.authError = '';
    const phone = state.regPhone.trim();
    const pass = state.regPassword;
    const passConfirm = state.regPasswordConfirm;

    if (!phone) { state.authError = 'Введите номер телефона'; render(); return; }
    if (!validatePhone(phone)) { state.authError = 'Введите корректный номер Кыргызстана (+996)'; render(); return; }
    if (pass.length < 6) { state.authError = 'Пароль должен быть не менее 6 символов'; render(); return; }
    if (pass !== passConfirm) { state.authError = 'Пароли не совпадают'; render(); return; }
    if (users.find(u => u.phone === phone)) { state.authError = 'Этот номер уже зарегистрирован'; render(); return; }

    state.regStep = 2;
    state.authError = '';
    render();
}

window.handleRegStep1 = handleRegStep1;

